module simple_neuron(
    input [4:0] bias, // 5 binary inputs representing bias
    output reg output_signal // output of the neuron
);
    always @* begin
        if (bias[0] + bias[1] + bias[2] + bias[3] + bias[4] >= 3) 
            output_signal = 1; 
        else 
            output_signal = 0; 
    end
endmodule
